import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"周边","description":"五山校区周边去处的简介页面","frontmatter":{"lang":"zh-CN","title":"周边","description":"五山校区周边去处的简介页面"},"headers":[],"relativePath":"infra/wushan/nearby.md","filePath":"infra/wushan/nearby.md","lastUpdated":1784896159000}`),a={name:`infra/wushan/nearby.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /infra/wushan/nearby.md for this page in Markdown format</div><h1 id="五山周边" tabindex="-1">五山周边 <a class="header-anchor" href="#五山周边" aria-label="Permalink to “五山周边”">​</a></h1><p>五山校区地处广州市区，校门外便是繁华的天河区，周边餐饮、购物、娱乐选择丰富。</p><h2 id="餐饮" tabindex="-1">餐饮 <a class="header-anchor" href="#餐饮" aria-label="Permalink to “餐饮”">​</a></h2><ul><li><strong>五山地铁站周边</strong>：从东门或东侧门出校即达五山站附近，周边遍布各类餐馆和小吃店</li><li><strong>天河客运站周边</strong>：从北区博学楼旁的北区北门出，步行数百米即到天河客运站，附近有天河新天地等商圈，餐饮选择丰富</li></ul><p>TODO: 日用采买与超市：周边大型超市、菜市场与水果店</p><h2 id="租房" tabindex="-1">租房 <a class="header-anchor" href="#租房" aria-label="Permalink to “租房”">​</a></h2><p>五山校区内的<strong>西秀村</strong>有教工宿舍可供出租，但价格相对较高。更多周边租房经验欢迎有相关经历的同学补充。</p><h2 id="交通接驳" tabindex="-1">交通接驳 <a class="header-anchor" href="#交通接驳" aria-label="Permalink to “交通接驳”">​</a></h2><h3 id="地铁" tabindex="-1">地铁 <a class="header-anchor" href="#地铁" aria-label="Permalink to “地铁”">​</a></h3><ul><li><strong>五山站（3号线）</strong>：西区、南区、东区最方便的地铁站，从东门或东侧门出即达</li><li><strong>天河客运站（3号线、6号线）</strong>：北区最方便的地铁站，从北区北门出步行数百米即达</li></ul><h3 id="跨校区交通" tabindex="-1">跨校区交通 <a class="header-anchor" href="#跨校区交通" aria-label="Permalink to “跨校区交通”">​</a></h3><p>往返大学城校区和国际校区最方便且廉价的方式是乘坐<strong>校巴</strong>。校巴从校内的图书馆等站点出发，经由快速路到达大学城校区及国际校区。</p><ul><li><strong>耗时</strong>：五山至大学城音乐厅约 45~60 分钟，至国际校区也在此区间内，早晚高峰可能延长</li><li><strong>班次</strong>：工作日班次较休息日更多</li></ul><h2 id="休闲娱乐" tabindex="-1">休闲娱乐 <a class="header-anchor" href="#休闲娱乐" aria-label="Permalink to “休闲娱乐”">​</a></h2><ul><li><strong>天河新天地</strong>：位于天河客运站附近，有商场、电影院等设施。</li><li>五山地铁站周边的娱乐去处欢迎有了解的同学补充。</li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};